if(empty($perpusAccess['allowed'])) return;
$message='';$error='';
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){
 try{
  perpus_check_csrf();$identifier=trim((string)($_POST['identifier']??''));if($identifier==='')throw new RuntimeException('RFID atau nomor anggota wajib dipindai.');
  $identity=sds_perpus_resolve_identity($conn,$identifier);if(!$identity)throw new RuntimeException('Kartu atau nomor anggota tidak ditemukan.');
  $member=$identity['member'];if(($member['status_keanggotaan']??'')!=='aktif')throw new RuntimeException('Keanggotaan tidak aktif.');$profile=$identity['profile']??sds_perpus_identity_profile($conn,(string)$identity['owner_type'],(int)$identity['owner_id'],$member);if(($identity['owner_type']??'')!=='legacy'&&empty($profile['aktif']))throw new RuntimeException('Pemilik kartu sedang nonaktif pada master SDS.');$memberId=(int)$member['id'];
  $allowDuplicate=0;$r=$conn->query("SELECT nilai FROM perpus_pengaturan WHERE kode='kunjungan_ganda_hari_ini'");if($r)$allowDuplicate=(int)($r->fetch_assoc()['nilai']??0);
  if(!$allowDuplicate){$stmt=$conn->prepare('SELECT id FROM perpus_kunjungan WHERE anggota_id=? AND DATE(waktu_kunjungan)=CURDATE() LIMIT 1');$stmt->bind_param('i',$memberId);$stmt->execute();$exists=$stmt->get_result()->fetch_assoc();$stmt->close();if($exists)throw new RuntimeException('Kunjungan anggota tersebut sudah tercatat hari ini.');}
  $source=trim((string)($identity['rfid']??''))!==''?'rfid':'manual';$stmt=$conn->prepare('INSERT INTO perpus_kunjungan (anggota_id,sumber) VALUES (?,?)');$stmt->bind_param('is',$memberId,$source);$stmt->execute();$stmt->close();
  $message='Kunjungan '.$profile['nama'].' berhasil dicatat.';
 }catch(Throwable $e){$error=$e->getMessage();}
}
$date=trim((string)($_GET['tanggal']??date('Y-m-d')));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date))$date=date('Y-m-d');$q=trim((string)($_GET['q']??''));
$rows=[];$stmt=$conn->prepare("SELECT k.*,a.pemilik_tipe,a.pemilik_id,a.nomor_anggota,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_kunjungan k JOIN perpus_anggota a ON a.id=k.anggota_id WHERE DATE(k.waktu_kunjungan)=? ORDER BY k.waktu_kunjungan DESC");$stmt->bind_param('s',$date);$stmt->execute();$res=$stmt->get_result();while($r=$res->fetch_assoc()){$p=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)$r['pemilik_id'],$r);$hay=mb_strtolower($p['nama'].' '.$p['identitas'].' '.$r['nomor_anggota']);if($q!==''&&mb_strpos($hay,mb_strtolower($q))===false)continue;$r['profile']=$p;$rows[]=$r;}$stmt->close();
$today=0;$r=$conn->query('SELECT COUNT(*) total FROM perpus_kunjungan WHERE DATE(waktu_kunjungan)=CURDATE()');if($r)$today=(int)($r->fetch_assoc()['total']??0);$month=0;$r=$conn->query('SELECT COUNT(*) total FROM perpus_kunjungan WHERE YEAR(waktu_kunjungan)=YEAR(CURDATE()) AND MONTH(waktu_kunjungan)=MONTH(CURDATE())');if($r)$month=(int)($r->fetch_assoc()['total']??0);$unique=0;$stmt=$conn->prepare('SELECT COUNT(DISTINCT anggota_id) total FROM perpus_kunjungan WHERE DATE(waktu_kunjungan)=?');$stmt->bind_param('s',$date);$stmt->execute();$unique=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();
require __DIR__ . '/../partials/master_page_style.php';
