<div class="scan-box mb-3"><form method="post" class="scan-row"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><div><label class="form-label">RFID / Nomor Anggota</label><input class="form-control scan-input" id="visitScan" name="identifier" autocomplete="off" placeholder="Tempel kartu untuk mencatat kunjungan" required></div><button class="btn btn-success align-self-end"><i data-feather="check-circle" class="me-1"></i>Catat Kunjungan</button></form></div>
