<div class="card"><div class="card-header"><form class="filter-row"><input class="form-control form-control-sm" name="q" value="<?=perpus_h($q)?>" placeholder="Cari nama, identitas, nomor anggota..."><input type="date" class="form-control form-control-sm" name="tanggal" value="<?=perpus_h($date)?>"><button class="btn btn-sm btn-primary">Tampilkan</button><a href="kunjungan" class="btn btn-sm btn-outline-secondary">Hari Ini</a></form></div><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Waktu</th><th>Pengunjung</th><th>Jenis / Unit</th><th>Nomor Anggota</th><th>Sumber</th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="5" class="text-center text-muted py-4">Belum ada kunjungan pada tanggal ini.</td></tr><?php endif;?><?php foreach($rows as $r):$p=$r['profile'];?><tr><td><strong><?=date('H:i:s',strtotime($r['waktu_kunjungan']))?></strong><div class="small text-muted"><?=date('d/m/Y',strtotime($r['waktu_kunjungan']))?></div></td><td><strong><?=perpus_h($p['nama'])?></strong><div class="small text-muted"><?=perpus_h($p['identitas'])?></div></td><td><?=perpus_h($p['unit'])?><div class="small text-muted"><?=perpus_h($p['detail'])?></div></td><td><code><?=perpus_h($r['nomor_anggota'])?></code></td><td><span class="badge <?=$r['sumber']==='rfid'?'bg-primary':'bg-secondary'?>"><?=perpus_h(strtoupper($r['sumber']))?></span></td></tr><?php endforeach;?></tbody></table></div></div></div><script>document.addEventListener('DOMContentLoaded',()=>document.getElementById('visitScan')?.focus());</script>
